let content;
try { content = JSON.parse($input.first().json.choices?.[0]?.message?.content || '{}'); } 
catch (e) { return [{ ...$input.first().json, trash: true, parse_error: true }]; }

const normalizedContact = (content.contact || '').toLowerCase();
const isJunkContact = !normalizedContact || normalizedContact.includes('sin ') || normalizedContact.includes('no hay') || normalizedContact.length < 5;
const isJunkTitle = (content.title_es || '').toLowerCase().length < 5 || (content.title_es || '').includes('Plaza');

if (content.trash === false && (isJunkContact || isJunkTitle || (!content.city && !content.country))) {
  content.trash = true;
  content.quality_fail = true;
}
return [{ ...$input.first().json, ...content }];
